import React from "react";

const Navbar = () => {
  // Function to scroll smoothly to a section
  const scrollToSection = (id) => {
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({ behavior: "smooth" });
    }
  };

  return (
    <nav
      style={{
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        padding: "1rem 2rem",
        backgroundColor: "#FF4C29",
        color: "#fff",
        position: "sticky",
        top: 0,
        zIndex: 1000,
      }}
    >
      {/* Logo */}
      <div style={{ fontWeight: "bold", fontSize: "1.2rem", cursor: "pointer" }} 
           onClick={() => scrollToSection("home")}>
        Sindhuja Kannuri
      </div>

      {/* Links */}
      
      <ul style={{ display: "flex", listStyle: "none", margin: 0, padding: 0 }}>
        <li style={{ margin: "0 1rem", cursor: "pointer" }} onClick={() => scrollToSection("home")}>Home</li>
        <li style={{ margin: "0 1rem", cursor: "pointer" }} onClick={() => scrollToSection("about")}>About</li>
        <li style={{ margin: "0 1rem", cursor: "pointer" }} onClick={() => scrollToSection("projects")}>Projects</li>
        <li style={{ margin: "0 1rem", cursor: "pointer" }} onClick={() => scrollToSection("contact")}>Contact</li>
      </ul>
      
    </nav>
  );
};

export default Navbar;
